    external fun uniffi_mmex_lib_checksum_method_accountmanager_create(
    ): Short
    external fun uniffi_mmex_lib_checksum_method_accountmanager_delete(
    ): Short
    external fun uniffi_mmex_lib_checksum_method_accountmanager_get_all(
    ): Short
    external fun uniffi_mmex_lib_checksum_method_accountmanager_get_all_json(
    ): Short
    external fun uniffi_mmex_lib_checksum_method_accountmanager_get_balance(
