     * Crea una nueva cuenta en la base de datos.
     */
    @Throws(AccountException::class)override fun `create`(`account`: Account): Account {
            return FfiConverterTypeAccount.lift(
    callWithHandle {
    uniffiRustCallWithError(AccountException) { _status ->
    UniffiLib.uniffi_mmex_lib_fn_method_accountmanager_create(
        it,
        FfiConverterTypeAccount.lower(`account`),_status)
}
