/**
 * @suppress
 */
public object FfiConverterTypeTransactionManager: FfiConverter<TransactionManager, Long> {
    override fun lower(value: TransactionManager): Long {
        return value.uniffiCloneHandle()
    }

    override fun lift(value: Long): TransactionManager {
        return TransactionManager(UniffiWithHandle, value)
    }

    override fun read(buf: ByteBuffer): TransactionManager {
        return lift(buf.getLong())
    }

    override fun allocationSize(value: TransactionManager) = 8UL

    override fun write(value: TransactionManager, buf: ByteBuffer) {
        buf.putLong(lower(value))
    }
}



