/**
 * Errores específicos relacionados con la gestión de cuentas.
 */
sealed class AccountException: kotlin.Exception() {
    
    /**
     * Error común propagado desde el core.
     */
    class Common(
        
        val v1: MmexException
        ) : AccountException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    /**
     * La cuenta con el ID proporcionado no existe.
     */
    class NotFound(
        
        val v1: AccountId
        ) : AccountException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    /**
     * Intento de crear una cuenta sin nombre.
     */
    class NameRequired(
        ) : AccountException() {
        override val message
            get() = ""
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<AccountException> {
        override fun lift(error_buf: RustBuffer.ByValue): AccountException = FfiConverterTypeAccountError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeAccountError : FfiConverterRustBuffer<AccountException> {
    override fun read(buf: ByteBuffer): AccountException {
        

        return when(buf.getInt()) {
            1 -> AccountException.Common(
                FfiConverterTypeMmexError.read(buf),
                )
            2 -> AccountException.NotFound(
                FfiConverterTypeAccountId.read(buf),
                )
            3 -> AccountException.NameRequired()
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: AccountException): ULong {
        return when(value) {
            is AccountException.Common -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeMmexError.allocationSize(value.v1)
            )
            is AccountException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeAccountId.allocationSize(value.v1)
            )
            is AccountException.NameRequired -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
        }
    }

    override fun write(value: AccountException, buf: ByteBuffer) {
        when(value) {
            is AccountException.Common -> {
                buf.putInt(1)
                FfiConverterTypeMmexError.write(value.v1, buf)
                Unit
            }
            is AccountException.NotFound -> {
                buf.putInt(2)
                FfiConverterTypeAccountId.write(value.v1, buf)
                Unit
            }
            is AccountException.NameRequired -> {
                buf.putInt(3)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



