        ) : TransactionException() {
        override val message
            get() = "v1=${ v1 }"
    }
    
    /**
     * El monto de la transacción no es válido (ej: negativo en contextos no permitidos).
     */
    class InvalidAmount(
        ) : TransactionException() {
        override val message
            get() = ""
    }
    
    /**
     * Error ocurrido durante la gestión de una transacción dividida (Split).
     */
    class SplitException(
        
        val v1: kotlin.String
        ) : TransactionException() {
        override val message
            get() = "v1=${ v1 }"
    }
    

    


    companion object ErrorHandler : UniffiRustCallStatusErrorHandler<TransactionException> {
        override fun lift(error_buf: RustBuffer.ByValue): TransactionException = FfiConverterTypeTransactionError.lift(error_buf)
    }

    
}

/**
 * @suppress
 */
public object FfiConverterTypeTransactionError : FfiConverterRustBuffer<TransactionException> {
    override fun read(buf: ByteBuffer): TransactionException {
        

        return when(buf.getInt()) {
            1 -> TransactionException.Common(
                FfiConverterTypeMmexError.read(buf),
                )
            2 -> TransactionException.NotFound(
                FfiConverterTypeTransactionId.read(buf),
                )
            3 -> TransactionException.InvalidAmount()
            4 -> TransactionException.SplitException(
                FfiConverterString.read(buf),
                )
            else -> throw RuntimeException("invalid error enum value, something is very wrong!!")
        }
    }

    override fun allocationSize(value: TransactionException): ULong {
        return when(value) {
            is TransactionException.Common -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeMmexError.allocationSize(value.v1)
            )
            is TransactionException.NotFound -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterTypeTransactionId.allocationSize(value.v1)
            )
            is TransactionException.InvalidAmount -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
            )
            is TransactionException.SplitException -> (
                // Add the size for the Int that specifies the variant plus the size needed for all fields
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: TransactionException, buf: ByteBuffer) {
        when(value) {
            is TransactionException.Common -> {
                buf.putInt(1)
                FfiConverterTypeMmexError.write(value.v1, buf)
                Unit
            }
            is TransactionException.NotFound -> {
                buf.putInt(2)
                FfiConverterTypeTransactionId.write(value.v1, buf)
                Unit
            }
            is TransactionException.InvalidAmount -> {
                buf.putInt(3)
                Unit
            }
            is TransactionException.SplitException -> {
                buf.putInt(4)
                FfiConverterString.write(value.v1, buf)
                Unit
            }
        }.let { /* this makes the `when` an expression, which ensures it is exhaustive */ }
    }

}



/**
 * Estado de reconciliación o validez de la transacción.
 */
sealed class TransactionStatus {
    
    /**
     * Sin estado específico (Pendiente).
     */
    object None : TransactionStatus()
    
    
    /**
     * Reconciliada con el banco.
     */
    object Reconciled : TransactionStatus()
    
    
    /**
     * Transacción anulada.
     */
    object Void : TransactionStatus()
    
    
    /**
     * Requiere seguimiento.
     */
    object FollowUp : TransactionStatus()
    
    
    /**
     * Marcada como duplicada.
     */
    object Duplicate : TransactionStatus()
    
    
    /**
     * Estado no reconocido.
     */
    data class Unknown(
        val v1: kotlin.String) : TransactionStatus()
        
    {
        

        companion object
    }
    

    

    
    


    companion object
}

/**
