public object FfiConverterTypeTransactionStatus : FfiConverterRustBuffer<TransactionStatus>{
    override fun read(buf: ByteBuffer): TransactionStatus {
        return when(buf.getInt()) {
            1 -> TransactionStatus.None
            2 -> TransactionStatus.Reconciled
            3 -> TransactionStatus.Void
            4 -> TransactionStatus.FollowUp
            5 -> TransactionStatus.Duplicate
            6 -> TransactionStatus.Unknown(
