            )
        }
        is TransactionStatus.Duplicate -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
            )
        }
        is TransactionStatus.Unknown -> {
            // Add the size for the Int that specifies the variant plus the size needed for all fields
            (
                4UL
                + FfiConverterString.allocationSize(value.v1)
            )
        }
    }

    override fun write(value: TransactionStatus, buf: ByteBuffer) {
        when(value) {
            is TransactionStatus.None -> {
                buf.putInt(1)
                Unit
            }
            is TransactionStatus.Reconciled -> {
                buf.putInt(2)
                Unit
            }
            is TransactionStatus.Void -> {
                buf.putInt(3)
