/**
 * @suppress
 */
public object FfiConverterSequenceTypeAccount: FfiConverterRustBuffer<List<Account>> {
    override fun read(buf: ByteBuffer): List<Account> {
        val len = buf.getInt()
        return List<Account>(len) {
            FfiConverterTypeAccount.read(buf)
        }
    }

    override fun allocationSize(value: List<Account>): ULong {
        val sizeForLength = 4UL
        val sizeForItems = value.map { FfiConverterTypeAccount.allocationSize(it) }.sum()
        return sizeForLength + sizeForItems
    }

